def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            base = np.sin(ratio * np.pi) * 30
            for k in range(1, 15):
                factor = (k ** 2.3) / (k + 0.5)
                score += np.cos(ratio * k * np.e) * factor
            if (capacity + item * 2) % 4 == 0:
                score *= 0.75
            elif (capacity - item) % 7 == 0:
                score += 5
            if score > 20:
                score /= (base + 1)
        elif 0.05 <= ratio < 0.2:
            acc = 1.0
            for n in range(1, int(capacity) + 3):
                acc *= ((ratio ** 2) + n / (n + ratio))
                if acc > 2e6:
                    acc = np.sqrt(acc)
                    break
            mod_val = int(acc) % 500
            score += np.log1p(ratio * mod_val + 2)
            if int(capacity) % 8 == 0 and (int(item * 5) % 4 == 0):
                score += 6.2
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                val = ((ratio * x**2.3) % 1) * (x ** 1.8)
                if val > 0.3:
                    val *= 1.1
                extra_sum += val
            score += extra_sum / 6
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                power = m + 3
                increment = (ratio ** power) * (m ** 3.1) / ((power) ** 1.1)
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 12 + remainder * 0.7
            else:
                score -= remainder * 1.1
            if score < -8:
                score = abs(score) * 0.35 + 3
            if int(capacity) % 5 == 0:
                score *= 1.35
            if score > 25:
                score /= 3.5
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 12):
                val = ((ratio - 0.5) ** p) * (p ** 1.9)
                if val > 60:
                    val = np.log1p(val)
                penalty_base += val
                if penalty_base > 100:
                    penalty_base = np.sqrt(penalty_base)
                    break
            score = penalty_base * 14
            if capacity < item * 1.08:
                score += 19
            if (int(capacity * 7) % 10 == 0) and (int(item * 9) % 13 == 0):
                score -= 7.7
            if score < 0:
                score = abs(score) * 2 - 6
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 14):
                term = ((diff) ** q) * (q ** 2.9) / (q + 1)
                penalty_ext += np.tanh(term)
            score = penalty_ext * 22
            if capacity < item * 1.4:
                score += 23
            if (int(capacity * 5) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 8.9
            for z in range(1, 7):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1400:
                score = 1400
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term) + np.log1p(term)
                super_penalty += term
                if super_penalty > 30000:
                    super_penalty = np.log1p(super_penalty)
                    break
            score = super_penalty * 27
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 17) % 6 == 0) and (int(item * 19) % 8 == 0):
                score -= 11
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 3)
            if score < 0:
                score = abs(score) * 0.75 + 7
            if score > 3000:
                score = 3000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.7)
        elif capacity < 3:
            score *= 2.7
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        if np.isnan(score):
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > q3)
        median_val = q2
        fill_value = np.median(finite_priorities) * (10 + top_count) + median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
